<script lang="ts">
  import type{ProjectRuntime}from'@simbot/runtime';
  import type{SimulationActionHandler}from'./simulation-action';
  type Row=Record<string,unknown>;
  let{runtime,version,busy=false,onaction=null,onchange=()=>{},portraitFor=()=>null}:{runtime:ProjectRuntime;version:number;busy?:boolean;onaction?:SimulationActionHandler|null;onchange?:()=>void;portraitFor?:(id:string,emotion?:string,outfit?:number)=>string|null}=$props();
  let tab=$state<'base'|'hire'|'dolls'|'echelon'|'operation'|'factory'|'shop'>('base'),selectedDoll=$state(''),selectedHire=$state(''),selectedEchelon=$state('echelon-1'),selectedMission=$state(''),selectedSlot=$state(0),pending=$state(false),message=$state('지휘 시스템 대기 중');
  const select=<T,>(id:string,fallback:T):T=>{version;try{return runtime.select(id)as T;}catch{return fallback;}};
  let status=$derived(select<Row>('gfl/status',{})),dolls=$derived(select<Row[]>('gfl/dolls',[])),echelons=$derived(select<Row[]>('gfl/echelons',[])),missions=$derived(select<Row[]>('gfl/missions',[])),queues=$derived(select<{manufacturing:Row[];repairs:Row[]}>('gfl/queues',{manufacturing:[],repairs:[]})),shop=$derived(select<{catalog:Row[];fairyCatalog:Row[];fairies:Row[]}>('gfl/shop',{catalog:[],fairyCatalog:[],fairies:[]})),hire=$derived(select<{offers:Row[];available:Row[];capacity:number;count:number;hiredToday:boolean;canRefresh:boolean;arrivals:Row[]}>('gfl/hire',{offers:[],available:[],capacity:0,count:0,hiredToday:false,canRefresh:true,arrivals:[]})),facilities=$derived(select<Row[]>('gfl/facilities',[]));
  let activeDoll=$derived(dolls.find(value=>value.id===(selectedDoll||dolls[0]?.id))),activeEchelon=$derived(echelons.find(value=>value.id===selectedEchelon)??echelons[0]),activeSlots=$derived(Array.isArray(activeEchelon?.slots)?activeEchelon.slots:[]),sortie=$derived(status.sortie&&typeof status.sortie==='object'?status.sortie as Row:null);
  async function act(id:string,params:Row={},mode:'ledger'|'narrated'='ledger'){if(pending||busy)return;pending=true;try{const log=onaction?await onaction({id,params,mode}):runtime.dispatch(id,params).log,last=log.at(-1)as Row|undefined;message=last?.ok===false?reason(String(last.reason??'unknown')):`${label(id)} 완료`;onchange();}finally{pending=false;}}
  const label=(id:string)=>({'gfl/start':'지휘관 등록','gfl/hire/refresh':'고용 목록 갱신','gfl/hire/contract':'인형 계약','gfl/hire/snipe':'저격 고용','gfl/hire/tick':'수송 도착','gfl/echelon/assign':'제대 편성','gfl/sortie/start':'작전 출격','gfl/sortie/engage':'적 조우','gfl/repair/start':'수복 시작','gfl/manufacture/start':'제조 시작','gfl/manufacture/tick':'제조 진행','gfl/repair/tick':'수복 진행','gfl/facility/upgrade':'시설 증설','gfl/mod/upgrade':'MOD 개조','gfl/shop/buy':'상점 구매','gfl/equipment/equip':'장비 장착','gfl/fairy/acquire':'요정 계약','gfl/fairy/assign':'요정 배치'}as Record<string,string>)[id]??id;
  const reason=(id:string)=>({'gfl_already_started':'이미 지휘 등록을 마쳤습니다.','gfl_hire_daily_limit':'오늘은 이미 인형 한 명을 영입했습니다.','gfl_hire_refresh_daily_limit':'오늘의 수동 목록 갱신을 이미 사용했습니다.','gfl_hire_capacity_full':'인형 숙소가 가득 찼습니다. 숙소를 증설하세요.','gfl_hire_funds_missing':'계약에 필요한 자금이 부족합니다.','gfl_hire_offer_missing':'현재 고용 목록에 없는 인형입니다.','gfl_doll_not_owned':'보유하지 않은 전술인형입니다.','gfl_slot_invalid':'잘못된 제대 슬롯입니다.','gfl_echelon_empty':'제대에 전술인형을 먼저 배치하세요.','gfl_power_too_low':'이 제대의 작전능력이 임무 요구치보다 낮습니다.','gfl_sortie_active':'이미 진행 중인 작전이 있습니다.','gfl_repair_not_needed':'수복이 필요하지 않습니다.','gfl_repair_cost_missing':'수복 부품이 부족합니다.','gfl_manufacture_cost_missing':'제조 자원이 부족합니다.','gfl_facility_cost_missing':'증설에 필요한 자금 또는 자원이 부족합니다.'}as Record<string,string>)[id]??`처리하지 못했습니다: ${id}`;
  const hp=(value:unknown)=>value&&typeof value==='object'?value as{cur?:number;max?:number}:{};
  const cost=(value:unknown)=>value&&typeof value==='object'?value as{gold?:number;res?:number}:null;
</script>

<div class="gfl" aria-label="소녀전선 지휘 콘솔">
  <header class="status"><div><span>DAY</span><b>{String(status.day??1)}</b></div><div><span>TIME</span><b>{String(status.time??8)}:00</b></div><div><span>FUNDS</span><b>{Number(status.funds??0).toLocaleString()}</b></div><div><span>RESOURCES</span><b>{Number(status.resources??0).toLocaleString()}</b></div><div><span>DOLLS</span><b>{String(status.dolls??0)}</b></div></header>
  {#if !status.started}
    <section class="boot"><p class="code">G&K TACTICAL COMMAND NETWORK</p><h2>소녀전선: 잔불</h2><p>원본 카드의 설정과 이미지를 Lucky 결정론 엔진으로 변환했습니다. 게임 수치는 엔진이 확정하고 AI는 장면과 대사를 연출합니다. 원본에서 회수한 값과 Lucky가 보정한 규칙의 목록은 진단 콘솔에서 확인할 수 있습니다.</p><div><button onclick={()=>act('gfl/start',{mode:'commander'})}>지휘관으로 시작</button><button onclick={()=>act('gfl/start',{mode:'doll'})}>전술인형으로 시작</button></div></section>
  {:else}
    <nav>{#each [['base','기지'],['hire','인형 고용'],['dolls','인형'],['echelon','제대'],['operation','작전'],['factory','제조·수복'],['shop','상점·장비']] as item}<button class:active={tab===item[0]} onclick={()=>tab=item[0]as typeof tab}>{item[1]}</button>{/each}</nav>
    <div class="workspace">
      {#if tab==='base'}
        <section class="stage">{#if activeDoll&&portraitFor(String(activeDoll.id))}<img src={portraitFor(String(activeDoll.id))!} alt={String(activeDoll.name)}/>{/if}<div class="scan"></div><div class="name">{String(activeDoll?.name??'KALINA')}</div></section>
        <section class="dialogue"><span>GRIFFIN BASE / COMMAND ROOM</span><p>{message}</p><div class="facility-grid">{#each facilities as facility}<button disabled={!facility.cost} onclick={()=>act('gfl/facility/upgrade',{facilityId:facility.id})}><b>{String(facility.name)}</b><small>LV.{String(facility.level)}{#if cost(facility.cost)} · 자금 {Number(cost(facility.cost)?.gold??0).toLocaleString()} / 자원 {Number(cost(facility.cost)?.res??0).toLocaleString()}{:else} · 최고 레벨{/if}</small></button>{/each}</div></section>
      {:else if tab==='hire'}
        <section class="list"><div class="hire-head"><div><h2>전술인형 고용</h2><p>숙소 {hire.count}/{hire.capacity} · 하루 한 명 계약 · 계약 후 다음 시간대 도착</p></div><button disabled={!hire.canRefresh&&hire.offers.length>0} onclick={()=>act('gfl/hire/refresh')}>{hire.offers.length?'목록 새로고침':'오늘의 목록 확인'}</button></div><div class="hire-grid">{#each hire.offers as offer}<article><span class="portrait">{#if portraitFor(String(offer.id))}<img src={portraitFor(String(offer.id))!} alt=""/>{/if}</span><div><b>{String(offer.name)}</b><small>{String(offer.class)} · ★{String(offer.grade)}</small><p>{String(offer.description??'')}</p></div><strong>{Number(offer.price??0).toLocaleString()} 자금</strong><button disabled={hire.hiredToday||hire.count>=hire.capacity} onclick={()=>act('gfl/hire/contract',{dollId:offer.id})}>계약</button></article>{/each}</div><h3>저격 고용</h3><div class="deploy"><select bind:value={selectedHire}><option value="">대상 선택</option>{#each hire.available as candidate}<option value={candidate.id}>{String(candidate.name)} · {Number(candidate.snipePrice).toLocaleString()}</option>{/each}</select><button disabled={!selectedHire||hire.hiredToday||hire.count>=hire.capacity} onclick={()=>act('gfl/hire/snipe',{dollId:selectedHire})}>지정 계약 (+3,000)</button>{#if hire.arrivals.length}<button onclick={()=>act('gfl/hire/tick')}>다음 시간대 · 수송 도착</button>{/if}</div></section>
      {:else if tab==='dolls'}
        <section class="list"><h2>전술인형 관리</h2><div class="doll-grid">{#each dolls as unit}<button class:selected={activeDoll?.id===unit.id} onclick={()=>selectedDoll=String(unit.id)}><span class="portrait">{#if portraitFor(String(unit.id))}<img src={portraitFor(String(unit.id))!} alt=""/>{/if}</span><b>{String(unit.name)}</b><small>{String(unit.class)} · ★{String(unit.grade)} · 전투력 {String(unit.power)}</small></button>{/each}</div></section>
        {#if activeDoll}<aside class="detail"><h3>{String(activeDoll.name)}</h3><p>{String(activeDoll.class)} / ★{String(activeDoll.grade)}</p><label>HP {String(hp(activeDoll.hp).cur??0)} / {String(hp(activeDoll.hp).max??0)}<progress value={hp(activeDoll.hp).cur??0} max={hp(activeDoll.hp).max??1}></progress></label><p>기분 {String(activeDoll.mood)} · 호감도 {String(activeDoll.affinity)} · MOD {String(activeDoll.mod)}</p><button onclick={()=>act('gfl/repair/start',{dollId:activeDoll.id})}>수복 투입</button><button onclick={()=>act('gfl/mod/upgrade',{dollId:activeDoll.id})}>MOD 개조</button></aside>{/if}
      {:else if tab==='echelon'}
        <section class="list"><h2>제대 편성</h2><div class="echelon-tabs">{#each echelons as entry}<button class:active={activeEchelon?.id===entry.id} onclick={()=>selectedEchelon=String(entry.id)}>{String(entry.name)} · {String(entry.power)}</button>{/each}</div>{#if activeEchelon}<div class="slots">{#each activeSlots as member,index}<button class:selected={selectedSlot===index} onclick={()=>selectedSlot=index}><span>SLOT {index+1}</span><b>{String(dolls.find(value=>value.id===member)?.name??'EMPTY')}</b></button>{/each}</div><h3>배치할 인형</h3><div class="roster">{#each dolls as unit}<button onclick={()=>act('gfl/echelon/assign',{echelonId:activeEchelon.id,slot:selectedSlot,dollId:unit.id})}>{String(unit.name)} · {String(unit.class)}</button>{/each}</div>{/if}</section>
      {:else if tab==='operation'}
        <section class="list"><h2>작전 지도</h2>{#if sortie}<div class="brief"><b>작전 진행 중 · {String(sortie.missionId)}</b><span>제대 {String(sortie.echelonId)} · 전투력 {String(sortie.power)}</span>{#if !sortie.engaged}<button onclick={()=>act('gfl/sortie/engage',{},'narrated')}>교전 개시</button>{/if}</div>{:else}<div class="mission-grid">{#each missions as operation}<button class:selected={selectedMission===operation.id} onclick={()=>selectedMission=String(operation.id)}><b>{String(operation.name)}</b><small>{String(operation.difficulty)} · 요구 {String(operation.power)}</small><span>{String(operation.enemy)}</span></button>{/each}</div><div class="deploy"><select bind:value={selectedEchelon}>{#each echelons as entry}<option value={entry.id}>{String(entry.name)} · {String(entry.power)}</option>{/each}</select><button disabled={!selectedMission} onclick={()=>act('gfl/sortie/start',{missionId:selectedMission,echelonId:selectedEchelon,command:'field'},'narrated')}>현장 지휘 출격</button></div>{/if}</section>
      {:else if tab==='factory'}
        <section class="list"><h2>제조·수복 대기열</h2><div class="factory-actions"><button onclick={()=>act('gfl/manufacture/start',{kind:'doll'})}>인형 제조</button><button onclick={()=>act('gfl/manufacture/start',{kind:'equipment'})}>장비 제조</button><button onclick={()=>act('gfl/manufacture/start',{kind:'doll',heavy:true})}>중형 제조</button></div><h3>제조</h3>{#each queues.manufacturing as job}<article><span>{String(job.kind)} · {String(job.status)}</span><b>{String(job.remaining)}단계</b>{#if job.status==='active'}<button onclick={()=>act('gfl/manufacture/tick',{jobId:job.id})}>시간 진행</button>{/if}</article>{/each}<h3>수복</h3>{#each queues.repairs as job}<article><span>{String(dolls.find(value=>value.id===job.dollId)?.name??job.dollId)} · {String(job.status)}</span><b>{String(job.remaining)}단계</b>{#if job.status==='active'}<button onclick={()=>act('gfl/repair/tick',{jobId:job.id})}>시간 진행</button>{/if}</article>{/each}</section>
      {:else}
        <section class="list"><h2>칼리나 상점 / 장비고</h2><div class="shop-grid">{#each shop.catalog as item}<article><div><b>{String(item.name)}</b><small>{String(item.kind)} · 보유 {String(item.owned??0)}</small></div><span>{Number(item.price??0).toLocaleString()} 자금</span><button onclick={()=>act('gfl/shop/buy',{itemId:item.id})}>구매</button>{#if item.kind==='equipment'&&Number(item.owned??0)>0&&activeDoll}<button onclick={()=>act('gfl/equipment/equip',{dollId:activeDoll.id,equipmentId:item.id})}>{String(activeDoll.name)} 장착</button>{/if}</article>{/each}</div><h2>전술요정</h2><div class="shop-grid">{#each shop.fairyCatalog as fairy}<article><div><b>{String(fairy.name)}</b><small>{shop.fairies.some(value=>value.id===fairy.id)?'계약 완료':'미계약'}</small></div>{#if !shop.fairies.some(value=>value.id===fairy.id)}<button onclick={()=>act('gfl/fairy/acquire',{fairyId:fairy.id})}>계약</button>{:else if activeEchelon}<button onclick={()=>act('gfl/fairy/assign',{fairyId:fairy.id,echelonId:activeEchelon.id})}>{String(activeEchelon.name)} 배치</button>{/if}</article>{/each}</div></section>
      {/if}
    </div>
  {/if}
</div>

<style>
  .gfl{--amber:#e5a84b;--cyan:#7cc8d8;min-height:32rem;border:1px solid #424a4d;background:linear-gradient(145deg,#141a1d,#090d0f);color:#d9e1df;font:13px/1.45 ui-monospace,'Noto Sans KR',sans-serif;overflow:hidden}.status{display:grid;grid-template-columns:repeat(5,1fr);border-bottom:1px solid #4b5554;background:#101719}.status div{display:grid;gap:2px;padding:8px 12px;border-right:1px solid #303a3a}.status span{font-size:9px;color:#7f9290;letter-spacing:.12em}.status b{color:var(--amber)}.boot{display:grid;place-items:center;min-height:28rem;padding:28px;text-align:center;background:radial-gradient(circle at 50% 30%,#263439 0,transparent 50%)}.boot h2{margin:0;color:var(--amber);font-size:28px;letter-spacing:.08em}.boot p{max-width:50ch;color:#9dacaa}.boot .code{color:var(--cyan);font-size:10px;letter-spacing:.2em}.boot div,.factory-actions,.roster,.deploy,.echelon-tabs{display:flex;gap:8px;flex-wrap:wrap}button,select{padding:8px 11px;border:1px solid #475353;border-radius:2px;background:#172024;color:#dce5e3}button:hover,button.active,button.selected{border-color:var(--amber);color:#ffd78e;background:#24251f}button:disabled{opacity:.4}nav{display:flex;border-bottom:1px solid #35403f;background:#111719}nav button{flex:1;border-width:0 1px 0 0;border-radius:0}.workspace{display:grid;grid-template-columns:minmax(0,1.25fr) minmax(18rem,.75fr);min-height:28rem}.stage{position:relative;min-height:28rem;overflow:hidden;background:radial-gradient(circle at 50% 55%,#354344,#121819 65%)}.stage img{position:absolute;inset:0;width:100%;height:100%;object-fit:contain;object-position:center bottom}.scan{position:absolute;inset:0;background:repeating-linear-gradient(0deg,transparent 0 3px,#8fd1d508 4px)}.name{position:absolute;left:18px;bottom:16px;padding:5px 10px;border-left:3px solid var(--amber);background:#080c0dcc;color:#fff;font-weight:700}.dialogue,.detail,.list{padding:16px}.dialogue{display:grid;align-content:end;gap:12px;border-left:1px solid #36403f;background:#0d1214}.dialogue>span{color:var(--cyan);font-size:10px}.dialogue>p{min-height:5rem;padding:12px;border:1px solid #3c4645;background:#151d1f}.facility-grid,.mission-grid,.doll-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:8px}.facility-grid button,.mission-grid button,.doll-grid button{display:grid;gap:4px;text-align:left}.facility-grid small,.mission-grid small,.doll-grid small,.shop-grid small,.hire-grid small{color:#8fa09d}.list{grid-column:1/-1;overflow:auto}.doll-grid .portrait{height:110px;overflow:hidden;background:#0d1213}.doll-grid img{width:100%;height:100%;object-fit:cover;object-position:top}.detail{border-left:1px solid #35403f;background:#0d1214}.detail label{display:grid;gap:4px}.detail progress{width:100%;accent-color:var(--amber)}.slots{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin:16px 0}.slots button{display:grid;min-height:90px;align-content:center}.slots span{font-size:9px;color:#72827f}.mission-grid button span{font-size:11px;color:#a8b3b0}.brief{display:grid;gap:8px;padding:14px;border:1px solid var(--amber);background:#262218}.deploy{margin-top:12px}.deploy select{min-width:12rem}.list article{display:grid;grid-template-columns:1fr auto auto;align-items:center;gap:8px;margin:6px 0;padding:9px;border:1px solid #333e3d;background:#12191b}.shop-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:8px}.shop-grid article{grid-template-columns:minmax(0,1fr) auto auto}.shop-grid article div{display:grid}.hire-head{display:flex;align-items:center;justify-content:space-between;gap:12px}.hire-head h2,.hire-head p{margin:0}.hire-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:8px;margin:14px 0}.hire-grid article{grid-template-columns:70px minmax(0,1fr);align-items:start}.hire-grid .portrait{grid-row:1/3;width:70px;height:100px;overflow:hidden;background:#0b1012}.hire-grid img{width:100%;height:100%;object-fit:cover;object-position:top}.hire-grid p{margin:5px 0;color:#9ba9a6}.hire-grid strong,.hire-grid button{grid-column:2}
  @container simulation-panel (max-width:44rem){.workspace{grid-template-columns:1fr}.stage{min-height:20rem}.dialogue,.detail{border-left:0;border-top:1px solid #35403f}.slots{grid-template-columns:repeat(5,minmax(70px,1fr));overflow:auto}.status{grid-template-columns:repeat(3,1fr)}}
  @media(max-width:700px){.gfl{min-height:100%}.status{grid-template-columns:repeat(3,1fr)}nav{overflow:auto}nav button{min-width:82px}.workspace{grid-template-columns:1fr}.stage{min-height:44vh}.dialogue,.detail{border-left:0;border-top:1px solid #35403f}.slots{grid-template-columns:repeat(5,90px);overflow:auto}.doll-grid,.mission-grid{grid-template-columns:1fr 1fr}}
  @media(orientation:landscape) and (max-height:600px){.gfl{min-height:calc(100dvh - 90px)}.workspace{grid-template-columns:1.2fr .8fr;min-height:calc(100dvh - 170px)}.stage{min-height:calc(100dvh - 170px)}.list{max-height:calc(100dvh - 170px)}}
</style>
